<?php include '_header.php'; if($_SERVER['REQUEST_METHOD']==='POST'){csrf_verify(); if(isset($_POST['delete'])) db()->prepare('DELETE FROM banners WHERE id=?')->execute([$_POST['delete']]); else { $img=upload_image('image',$_POST['old_image']?:null); $data=[$_POST['title'],$_POST['subtitle'],$img,$_POST['link'],$_POST['sort_order'],isset($_POST['is_active'])?1:0]; if($_POST['id']) db()->prepare('UPDATE banners SET title=?,subtitle=?,image=?,link=?,sort_order=?,is_active=? WHERE id=?')->execute([...$data,$_POST['id']]); else db()->prepare('INSERT INTO banners(title,subtitle,image,link,sort_order,is_active) VALUES(?,?,?,?,?,?)')->execute($data);} redirect('banners.php');} $edit=null; if(isset($_GET['edit'])){$q=db()->prepare('SELECT * FROM banners WHERE id=?');$q->execute([(int)$_GET['edit']]);$edit=$q->fetch();} $rows=db()->query('SELECT * FROM banners ORDER BY sort_order,id DESC')->fetchAll(); ?>
<h1>CRUD Banner</h1><form method="post" enctype="multipart/form-data" class="row g-2 premium-card p-3 mb-4"><input type="hidden" name="_csrf" value="<?=csrf_token()?>"><input type="hidden" name="id" value="<?=e($edit['id']??'')?>"><input type="hidden" name="old_image" value="<?=e($edit['image']??'')?>"><div class="col-md-3"><input class="form-control" name="title" placeholder="Judul" value="<?=e($edit['title']??'')?>" required></div><div class="col-md-3"><input class="form-control" name="subtitle" placeholder="Subtitle" value="<?=e($edit['subtitle']??'')?>"></div><div class="col-md-3"><input class="form-control" name="link" placeholder="Link" value="<?=e($edit['link']??'')?>"></div><div class="col-md-1"><input class="form-control" name="sort_order" type="number" value="<?=e($edit['sort_order']??'0')?>"></div><div class="col-md-2"><input class="form-control" name="image" type="file" accept="image/*"></div><label><input type="checkbox" name="is_active" checked> Aktif</label><div><button class="btn btn-light">Simpan Banner</button><?php if($edit): ?> <a class="btn btn-outline-light" href="banners.php">Batal Edit</a><?php endif; ?></div></form><table class="table table-dark"><tr><th>Judul</th><th>Aktif</th><th></th></tr><?php foreach($rows as $r):?><tr><td><?=e($r['title'])?></td><td><?=$r['is_active']?'Ya':'Tidak'?></td><td><a class="btn btn-sm btn-warning" href="banners.php?edit=<?=$r['id']?>">Edit</a> <form class="d-inline" method="post"><input type="hidden" name="_csrf" value="<?=csrf_token()?>"><button class="btn btn-sm btn-danger" name="delete" value="<?=$r['id']?>">Hapus</button></form></td></tr><?php endforeach;?></table><?php include '_footer.php'; ?>
